(7, 'Air Terjun Curup', 'Kabupaten Rejang Lebong', 'alam', 0, 'Air terjun bertingkat yang dikelilingi hutan hijau yang asri. Aliran airnya yang jernih dan segar menjadi surga tersembunyi bagi pecinta alam di Bengkulu.', 'data:image/jpeg;base64,', '2026-05-01 23:25:58');
INSERT INTO `wisata` (`id`, `nama`, `lokasi`, `kategori`, `rating`, `deskripsi`, `gambar`, `created_at`) VALUES
(8, 'Rumah Pengasingan Bung Karno', 'Kota Bengkulu', 'sejarah', 0, 'Rumah bersejarah tempat Presiden pertama RI, Ir. Soekarno, menjalani masa pengasingan dari tahun 1938–1942. Kini menjadi museum yang menyimpan berbagai koleksi bersejarah.', 'data:image/jpeg;base64,', '2026-05-01 23:26:42');
INSERT INTO `wisata` (`id`, `nama`, `lokasi`, `kategori`, `rating`, `deskripsi`, `gambar`, `created_at`) VALUES
(9, 'Taman Nasional Kerinci Seblat', 'Kabupaten Lebong', 'alam', 0, 'Kawasan konservasi terluas di Sumatera yang menjadi habitat Bunga Rafflesia Arnoldii, bunga terbesar di dunia. Hutan tropis lebat dengan keanekaragaman hayati yang luar biasa.', 'data:image/jpeg;base64,', '2026-05-01 23:27:29');
INSERT INTO `wisata` (`id`, `nama`, `lokasi`, `kategori`, `rating`, `deskripsi`, `gambar`, `created_at`) VALUES
(10, 'Pantai Tapak Paderi', 'Kota Bengkulu', 'pantai', 0, 'Pantai eksotis dengan ombak yang tenang, berpasir kecokelatan, dan panorama samudra Hindia yang memukau. Tempat terbaik untuk menikmati sunrise di Bengkulu.', 'data:image/jpeg;base64,', '2026-05-01 23:28:30');
INSERT INTO `wisata` (`id`, `nama`, `lokasi`, `kategori`, `rating`, `deskripsi`, `gambar`, `created_at`) VALUES
(11, 'Bukit Kaba', 'Kabupaten Rejang Lebong', 'alam', 0, 'Gunung berapi aktif yang menawarkan pengalaman mendaki yang luar biasa. Di puncaknya terdapat kawah belerang dan pemandangan alam yang menakjubkan di ketinggian 1938 mdpl.', 'data:image/jpeg;base64,', '2026-05-01 23:29:12');
INSERT INTO `wisata` (`id`, `nama`, `lokasi`, `kategori`, `rating`, `deskripsi`, `gambar`, `created_at`) VALUES
(12, 'Benteng Marlborough', 'Kota Bengkulu', 'sejarah', 0, 'Benteng peninggalan kolonial Inggris yang dibangun pada abad ke-18. Merupakan salah satu benteng terbesar di Asia Tenggara dan menjadi ikon sejarah Bengkulu.', 'data:image/jpeg;base64,', '2026-05-01 23:30:01');
INSERT INTO `wisata` (`id`, `nama`, `lokasi`, `kategori`, `rating`, `deskripsi`, `gambar`, `created_at`) VALUES
(13, 'Pantai Panjang', 'Kota Bengkulu', 'pantai', 0, 'Pantai berpasir putih yang membentang sekitar 7 km, menjadi salah satu pantai terpanjang dan terindah di Bengkulu. Cocok untuk bersantai menikmati sunset dan bermain air.', 'data:image/jpeg;base64,', '2026-05-01 23:31:00');

